$files = @(
  @{ path = "packages/openai/src/index.ts"; b64 = "" }
  @{ path = "packages/openai/src/types.ts"; b64 = "" }
  @{ path = "packages/openai/src/agents.ts"; b64 = "" }
  @{ path = "packages/openai/src/functions.ts"; b64 = "" }
  @{ path = "packages/openai/test/openai.test.ts"; b64 = "" }
  @{ path = "packages/openai/examples/agents-sdk-demo.ts"; b64 = "" }
  @{ path = "packages/openai/examples/function-calling-demo.ts"; b64 = "" }
  @{ path = "packages/openai/package.json"; b64 = "" }
  @{ path = "packages/openai/tsconfig.json"; b64 = "" }
  @{ path = "packages/openai/README.md"; b64 = "" }
)
foreach ($file in $files) {
    $target = [System.IO.Path]::GetFullPath([System.IO.Path]::Combine($PWD, $file.path))
    $dir = [System.IO.Path]::GetDirectoryName($target)
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    [System.IO.File]::WriteAllBytes($target, [System.Convert]::FromBase64String($file.b64))
    Write-Host "wrote $($file.path)"
}
Write-Host "Done."
